import { initializeApp } from 'https://www.gstatic.com/firebasejs/12.16.0/firebase-app.js';
import { getAuth, setPersistence, browserLocalPersistence, browserSessionPersistence, signInWithEmailAndPassword, signInAnonymously, linkWithCredential, EmailAuthProvider, onAuthStateChanged, signOut } from 'https://www.gstatic.com/firebasejs/12.16.0/firebase-auth.js';
import { getFirestore, doc, getDoc, collection, getDocs, serverTimestamp, runTransaction } from 'https://www.gstatic.com/firebasejs/12.16.0/firebase-firestore.js';

const firebaseConfig={apiKey:'AIzaSyDXxh48yiFHMqL4dH82-fTg0dZXqFi1ud4',authDomain:'cc-database-19dba.firebaseapp.com',projectId:'cc-database-19dba',appId:'1:793192077235:web:ff335960e78a39ac971dc6'};
const app=initializeApp(firebaseConfig),auth=getAuth(app),db=getFirestore(app),root=document.getElementById('app');
const aliasFor=u=>`${u.trim().toLowerCase().replace(/[^a-z0-9._-]/g,'')}@accounts.canela.internal`;
const hash=async v=>Array.from(new Uint8Array(await crypto.subtle.digest('SHA-256',new TextEncoder().encode(v.trim().toUpperCase())))).map(b=>b.toString(16).padStart(2,'0')).join('');
const esc=v=>String(v??'').replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c]));
let account=null,currentView='dashboard';
function nav(id,label,icon){return `<button data-view="${id}" class="nav-item ${currentView===id?'active':''}"><span>${icon}</span>${label}</button>`}
function shell(content){root.innerHTML=`<header class="topbar"><div class="brand"><div class="brand-mark">CC</div><div><strong>Canela Portal</strong><span>${esc(account?.organizationalRank||'Administration')}</span></div></div><button id="menuBtn" class="icon-btn">☰</button></header><div class="layout"><aside id="sidebar"><nav>${nav('dashboard','Dashboard','⌂')}${nav('staff','Staff Directory','👥')}${nav('personnel','Personnel','↕')}${nav('compliance','Compliance','⚖')}${nav('alliances','Alliances','🤝')}${nav('training','Training & HR','🎓')}${nav('policies','Policies','📚')}${account?.systemRoles?.includes('SYSTEM_ADMINISTRATOR')?nav('system','System Admin','⚙'):''}</nav><button id="logoutBtn" class="logout">Sign out</button></aside><main>${content}</main></div>`;document.getElementById('menuBtn').onclick=()=>document.getElementById('sidebar').classList.toggle('open');document.getElementById('logoutBtn').onclick=()=>signOut(auth);document.querySelectorAll('[data-view]').forEach(b=>b.onclick=()=>{currentView=b.dataset.view;renderPortal()});}
async function count(name){try{return (await getDocs(collection(db,name))).size}catch{return 0}}
function moduleCard(id,title,text){return `<button class="module-card" data-view="${id}"><strong>${title}</strong><span>${text}</span></button>`}
async function dashboard(){const [staff,cases,appeals,alliances]=await Promise.all([count('staffProfiles'),count('disciplinaryCases'),count('appeals'),count('alliances')]);return `<section class="hero"><p>CANELA CORPORATION</p><h1>Welcome, ${esc(account?.displayName||account?.portalUsername||'Staff Member')}</h1><span>Secure organizational operations portal</span></section><section class="cards"><article><small>Staff profiles</small><strong>${staff}</strong><span>Current database entries</span></article><article><small>Disciplinary cases</small><strong>${cases}</strong><span>Recorded cases</span></article><article><small>Appeals</small><strong>${appeals}</strong><span>Submitted reviews</span></article><article><small>Alliances</small><strong>${alliances}</strong><span>Partnership records</span></article></section><section class="panel"><h2>Portal modules</h2><div class="module-grid">${moduleCard('staff','Staff Management','Profiles, ranks, departments, quotas and personnel history.')}${moduleCard('compliance','Compliance','Punishments, offences, blacklists and appeals.')}${moduleCard('alliances','External Relations','Alliance representatives, partnership status and strikes.')}${moduleCard('training','Workforce & HR','Training, certifications, reviews, goals and attendance.')}</div></section>`}
async function listCollection(name,title,fields){let docs=[];try{docs=(await getDocs(collection(db,name))).docs.map(d=>({id:d.id,...d.data()}))}catch{return `<section class="panel"><h1>${title}</h1><p class="error">Unable to load this collection. Check Firestore rules.</p></section>`}return `<section class="panel"><div class="section-head"><div><p>DATABASE MODULE</p><h1>${title}</h1></div><span>${docs.length} records</span></div>${docs.length?`<div class="table-wrap"><table><thead><tr>${fields.map(f=>`<th>${f.label}</th>`).join('')}</tr></thead><tbody>${docs.map(x=>`<tr>${fields.map(f=>`<td>${esc(typeof f.value==='function'?f.value(x):x[f.value])}</td>`).join('')}</tr>`).join('')}</tbody></table></div>`:'<div class="empty">No records have been added yet.</div>'}</section>`}
async function renderPortal(){let content='';if(currentView==='dashboard')content=await dashboard();else if(currentView==='staff')content=await listCollection('staffProfiles','Staff Directory',[{label:'Name',value:x=>x.displayName||x.robloxUsername},{label:'Roblox',value:'robloxUsername'},{label:'Discord',value:'discordUsername'},{label:'Rank',value:x=>x.rankName||x.organizationalRank},{label:'Status',value:x=>x.staffStatus||x.status}]);else if(currentView==='personnel')content=await listCollection('personnelActions','Personnel Actions',[{label:'Staff',value:'staffName'},{label:'Action',value:'actionType'},{label:'Reason',value:'reason'},{label:'Status',value:'status'}]);else if(currentView==='compliance')content=await listCollection('disciplinaryCases','Compliance & Discipline',[{label:'Subject',value:'subjectName'},{label:'Offence',value:'offenceName'},{label:'Recommendation',value:'recommendedAction'},{label:'Status',value:'status'}]);else if(currentView==='alliances')content=await listCollection('alliances','Alliance Management',[{label:'Alliance',value:'name'},{label:'Canela Rep',value:'canelaRepresentative'},{label:'Partner Rep',value:'partnerRepresentative'},{label:'Status',value:'status'}]);else if(currentView==='training')content=await listCollection('courses','Training & Workforce',[{label:'Course',value:'title'},{label:'Category',value:'category'},{label:'Passing score',value:x=>x.passingScore?`${x.passingScore}%`:'—'},{label:'Status',value:'status'}]);else if(currentView==='policies')content=await listCollection('documents','Policy Library',[{label:'Title',value:'title'},{label:'Type',value:'type'},{label:'Version',value:'version'},{label:'Visibility',value:'visibility'}]);else content=`<section class="panel"><p>SYSTEM ADMINISTRATION</p><h1>Account overview</h1><dl class="details"><dt>Display name</dt><dd>${esc(account.displayName)}</dd><dt>Portal username</dt><dd>${esc(account.portalUsername)}</dd><dt>Rank</dt><dd>${esc(account.organizationalRank)}</dd><dt>Status</dt><dd>${esc(account.portalStatus)}</dd><dt>System roles</dt><dd>${esc((account.systemRoles||[]).join(', ')||'None')}</dd></dl></section>`;shell(content);document.querySelectorAll('.module-card').forEach(b=>b.onclick=()=>{currentView=b.dataset.view;renderPortal()});}
function authPage(message=''){root.innerHTML=`<main class="auth-page"><section class="auth-card"><div class="brand-mark large">CC</div><p>CANELA CORPORATION</p><h1>Administration Portal</h1><span>Authorized personnel only</span>${message?`<div class="alert">${esc(message)}</div>`:''}<div class="auth-tabs"><button id="loginTab" class="active">Sign in</button><button id="activateTab">Activate</button></div><form id="loginForm"><label>Portal username<input name="username" autocomplete="username" required></label><label>Password<input name="password" type="password" autocomplete="current-password" required></label><label class="check"><input name="remember" type="checkbox" checked>Remember this device</label><button>Sign in</button></form><form id="activateForm" hidden><label>Activation code<input name="code" required></label><label>Choose username<input name="username" minlength="4" maxlength="24" required></label><label>Create password<input name="password" type="password" minlength="10" required></label><label>Confirm password<input name="confirm" type="password" minlength="10" required></label><button>Activate account</button></form></section></main>`;const lf=document.getElementById('loginForm'),af=document.getElementById('activateForm');document.getElementById('loginTab').onclick=()=>{lf.hidden=false;af.hidden=true};document.getElementById('activateTab').onclick=()=>{lf.hidden=true;af.hidden=false};lf.onsubmit=login;af.onsubmit=activate;}
async function login(e){e.preventDefault();const f=new FormData(e.currentTarget);try{await setPersistence(auth,f.get('remember')?browserLocalPersistence:browserSessionPersistence);await signInWithEmailAndPassword(auth,aliasFor(String(f.get('username'))),String(f.get('password')))}catch{authPage('Sign-in failed. Check your username and password.')}}
async function activate(e){e.preventDefault();const f=new FormData(e.currentTarget),password=String(f.get('password')),confirm=String(f.get('confirm'));if(password!==confirm)return authPage('Passwords do not match.');try{const codeHash=await hash(String(f.get('code'))),codeRef=doc(db,'activationCodes',codeHash),snap=await getDoc(codeRef);if(!snap.exists()||snap.data().status!=='PENDING')throw new Error();const anon=await signInAnonymously(auth),linked=await linkWithCredential(anon.user,EmailAuthProvider.credential(aliasFor(String(f.get('username'))),password));await runTransaction(db,async tx=>{const fresh=await tx.get(codeRef);if(!fresh.exists()||fresh.data().status!=='PENDING')throw new Error();tx.set(doc(db,'portalAccounts',linked.user.uid),{displayName:fresh.data().displayName||f.get('username'),portalUsername:String(f.get('username')).trim().toLowerCase(),organizationalRank:fresh.data().organizationalRank||'Staff',portalStatus:'ACTIVE',staffProfileId:fresh.data().staffProfileId||'',systemRoles:fresh.data().systemRoles||[],permissions:fresh.data().permissions||[],createdAt:serverTimestamp()});tx.set(doc(db,'portalUsernames',String(f.get('username')).trim().toLowerCase()),{uid:linked.user.uid,createdAt:serverTimestamp()});tx.update(codeRef,{status:'USED',usedByUid:linked.user.uid,usedAt:serverTimestamp()})})}catch{try{await signOut(auth)}catch{}authPage('Activation failed. Confirm the code is valid and the username is unused.')}}
onAuthStateChanged(auth,async user=>{if(!user){account=null;authPage();return}try{const snap=await getDoc(doc(db,'portalAccounts',user.uid));if(!snap.exists()||snap.data().portalStatus!=='ACTIVE'){await signOut(auth);return}account=snap.data();renderPortal()}catch{authPage('The portal could not verify your account.')}});